"  // Estados para as sub-abas de Resultados e Questionários Customizados
  const [resultsSubTab, setResultsSubTab] = useState<'relatorios' | 'guia' | 'criar'>('relatorios');
  const [selectedJobForCustom, setSelectedJobForCustom] = useState<string>('');
  const [customQuestions, setCustomQuestions] = useState<any[]>([]);
  const [isCustomTestModalOpen, setIsCustomTestModalOpen] = useState(false);
  const [selectedApplicantForCustomTest, setSelectedApplicantForCustomTest] = useState<any>(null);

  const handleJobChangeForCustomQuestions = (jobId: string) => {
    setSelectedJobForCustom(jobId);
    if (!jobId) {
      setCustomQuestions([]);
      return;
    }
    const targetJob = jobs.find(j => j.id === jobId);
    if (targetJob) {
      const qList = getCustomQuestionsFromJobDescription(targetJob.description || '');
      setCustomQuestions(qList);
    } else {
      setCustomQuestions([]);
    }
  };"
